const config = $('Tag IDs ermitteln1').first().json;
const docs = $json.results || [];

const unpaidInvoices = docs.filter(doc => {
  const tags = doc.tags || [];
  return !tags.includes(config.paid_tag_id);
});

return unpaidInvoices.map(doc => ({
  json: {
    ...config,
    doc_id: doc.id,
    doc_title: doc.title,
    doc_created: doc.created,
    doc_document_date: doc.document_date,
    doc_tags: doc.tags || []
  }
}));

const inputItems = $input.all();
const metaItems = $('Unbezahlte Rechnungen aufteilen').all();

function parseGermanDate(raw) {
  if (!raw) return null;
  const s = String(raw).trim();

  let m = s.match(/(\d{1,2})\.(\d{1,2})\.(\d{2,4})/);
  if (m) {
    let year = Number(m[3]);
    if (year < 100) year += 2000;
    const month = Number(m[2]);
    const day = Number(m[1]);
    const d = new Date(Date.UTC(year, month - 1, day));
    if (!isNaN(d)) return d.toISOString().slice(0, 10);
  }

  m = s.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (m) {
    const d = new Date(`${m[1]}-${m[2]}-${m[3]}T00:00:00Z`);
    if (!isNaN(d)) return d.toISOString().slice(0, 10);
  }

  return null;
}

function addDays(dateString, days) {
  const d = new Date(`${dateString}T00:00:00Z`);
  d.setUTCDate(d.getUTCDate() + days);
  return d.toISOString().slice(0, 10);
}

function daysBetween(fromDate, toDate) {
  const a = new Date(`${fromDate}T00:00:00Z`);
  const b = new Date(`${toDate}T00:00:00Z`);
  return Math.round((b - a) / 86400000);
}

function toNumberGerman(value) {
  if (!value) return null;
  let s = String(value)
    .replace(/\s/g, '')
    .replace(/EUR/gi, '')
    .replace(/€/g, '')
    .trim();

  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }

  const n = Number(s.replace(/[^0-9.-]/g, ''));
  return Number.isFinite(n) ? Math.abs(n) : null;
}

function findAmount(text) {
  const input = String(text || '');

  const patterns = [
    /(?:gesamtbetrag|gesamt\s*betrag|betrag\s*gesamt|zu\s*zahlen|zahlbetrag|rechnungsbetrag|endsumme|summe|total|offener\s*betrag|fälliger\s*betrag)\D{0,60}(\d{1,6}(?:\.\d{3})*,\d{2})\s?(?:€|eur)?/i,
    /(\d{1,6}(?:\.\d{3})*,\d{2})\s?(?:€|eur)\D{0,40}(?:gesamtbetrag|gesamt|zu\s*zahlen|zahlbetrag|rechnungsbetrag|summe|total)/i
  ];

  for (const p of patterns) {
    const m = input.match(p);
    if (m?.[1]) {
      const n = toNumberGerman(m[1]);
      if (n && n > 0) return n;
    }
  }

  const matches = input.match(/\d{1,6}(?:\.\d{3})*,\d{2}\s?(?:€|EUR)?/gi) || [];
  const amounts = matches
    .map(toNumberGerman)
    .filter(n => n && n > 0)
    .sort((a, b) => b - a);

  return amounts[0] || null;
}

function findDueDate(text, invoiceDate) {
  const input = String(text || '').replace(/\s+/g, ' ');

  const directPatterns = [
    /(?:fällig(?:keit)?(?:\s*am|\s*zum)?|zahlbar\s*bis|zu\s*zahlen\s*bis|bitte\s*(?:zahlen|überweisen)\s*bis|zahlung\s*bis|überweisen\s*bis|spätestens\s*bis|zahlungsziel)\D{0,80}(\d{1,2}\.\d{1,2}\.\d{2,4})/i,
    /(?:due\s*date|payment\s*due|payable\s*until)\D{0,80}(\d{1,2}\.\d{1,2}\.\d{2,4})/i,
    /(?:fällig(?:keit)?(?:\s*am|\s*zum)?|zahlbar\s*bis|zu\s*zahlen\s*bis|zahlung\s*bis|spätestens\s*bis|zahlungsziel)\D{0,80}(\d{4}-\d{2}-\d{2})/i
  ];

  for (const p of directPatterns) {
    const m = input.match(p);
    if (m?.[1]) {
      const parsed = parseGermanDate(m[1]);
      if (parsed) return { due_date: parsed, source: 'direktes Fälligkeitsdatum im Text' };
    }
  }

  const relativePatterns = [
    /(?:zahlbar|zahlung|fällig|zahlungsziel)\D{0,80}(?:innerhalb\s*von\s*)?(\d{1,3})\s*(?:tagen|tage|kalendertagen|werktagen)/i,
    /innerhalb\s*von\s*(\d{1,3})\s*(?:tagen|tage|kalendertagen|werktagen)/i
  ];

  for (const p of relativePatterns) {
    const m = input.match(p);
    if (m?.[1] && invoiceDate) {
      const days = Number(m[1]);
      if (Number.isFinite(days) && days > 0) {
        return {
          due_date: addDays(invoiceDate, days),
          source: `relatives Zahlungsziel: ${days} Tage ab Rechnungsdatum`
        };
      }
    }
  }

  return { due_date: null, source: 'kein Fälligkeitsdatum erkannt' };
}

const today = new Date().toISOString().slice(0, 10);

return inputItems.map((item, index) => {
  const detail = item.json;
  const meta = metaItems[index].json;

  const text = [
    detail.title,
    detail.correspondent_name,
    detail.content
  ].filter(Boolean).join('\n');

  const invoiceDate = detail.document_date || detail.created?.slice(0, 10) || meta.doc_document_date || meta.doc_created?.slice(0, 10) || today;
  const amount = findAmount(text);
  const due = findDueDate(text, invoiceDate);

  let dueStatus = 'unknown';
  let daysUntilDue = null;
  let relevant = false;

  if (due.due_date) {
    daysUntilDue = daysBetween(today, due.due_date);

    if (daysUntilDue < 0) {
      dueStatus = 'overdue';
      relevant = true;
    } else if (daysUntilDue <= Number(meta.due_days_ahead)) {
      dueStatus = 'due_soon';
      relevant = true;
    } else {
      dueStatus = 'later';
    }
  }

  return {
    json: {
      ...meta,
      detail,
      title: detail.title,
      correspondent: detail.correspondent_name || '',
      invoice_date: invoiceDate,
      amount,
      due_date: due.due_date,
      due_date_source: due.source,
      due_status: dueStatus,
      days_until_due: daysUntilDue,
      relevant_for_notification: relevant
    }
  };
});

const items = $input.all().map(i => i.json);
const config = $('Tag IDs ermitteln1').first().json;

const relevant = items
  .filter(i => i.relevant_for_notification === true)
  .sort((a, b) => String(a.due_date).localeCompare(String(b.due_date)));

const unknownDue = items
  .filter(i => !i.due_date)
  .slice(0, 10);

function formatAmount(value) {
  if (value === null || value === undefined || value === '') return 'Betrag unbekannt';
  return Number(value).toFixed(2).replace('.', ',') + ' €';
}

function statusText(item) {
  if (item.due_status === 'overdue') {
    return `ÜBERFÄLLIG seit ${Math.abs(item.days_until_due)} Tag(en)`;
  }
  if (item.days_until_due === 0) return 'HEUTE fällig';
  if (item.days_until_due === 1) return 'MORGEN fällig';
  return `in ${item.days_until_due} Tag(en) fällig`;
}

let message = '';

if (relevant.length === 0) {
  message = `Keine unbezahlten Rechnungen gefunden, die überfällig sind oder in den nächsten ${config.due_days_ahead} Tagen fällig werden.`;
} else {
  message += `Fällige Rechnungen / nächste ${config.due_days_ahead} Tage: ${relevant.length}\n\n`;

  for (const item of relevant) {
    message += `• ${statusText(item)}\n`;
    message += `${item.title || 'Ohne Titel'}\n`;
    if (item.correspondent) message += `Empfänger: ${item.correspondent}\n`;
    message += `Fällig: ${item.due_date}\n`;
    message += `Betrag: ${formatAmount(item.amount)}\n`;
    message += `Paperless-ID: ${item.detail.id}\n\n`;
  }
}

if (unknownDue.length > 0) {
  message += `\nHinweis: Bei ${unknownDue.length} Rechnung(en) konnte kein Fälligkeitsdatum erkannt werden. Beispiele:\n`;
  for (const item of unknownDue.slice(0, 5)) {
    message += `- ${item.title || 'Ohne Titel'} / ID ${item.detail.id}\n`;
  }
}

// Pushover hat ein Nachrichtenlimit. Sicherheitshalber kürzen.
if (message.length > 950) {
  message = message.slice(0, 920) + '\n... gekürzt. Bitte Paperless prüfen.';
}

return [
  {
    json: {
      ...config,
      due_count: relevant.length,
      unknown_due_count: unknownDue.length,
      pushover_title: relevant.length > 0 ? 'Fällige Rechnungen' : 'Rechnungsprüfung',
      pushover_message: message,
      should_notify: relevant.length > 0 || unknownDue.length > 0
    }
  }
];

const required = [
  'PAPERLESS_URL',
  'PAPERLESS_TOKEN',
  'PUSHOVER_APP_TOKEN',
  'PUSHOVER_USER_KEY'
];

for (const key of required) {
  if (!$vars[key]) {
    throw new Error(`n8n Variable fehlt: ${key}`);
  }
}

return [
  {
    json: {
      paperless_url: String($vars.PAPERLESS_URL).replace(/\/$/, ''),
      paperless_token: $vars.PAPERLESS_TOKEN,

      pushover_app_token: $vars.PUSHOVER_APP_TOKEN,
      pushover_user_key: $vars.PUSHOVER_USER_KEY,

      invoice_tag_name: $vars.PAPERLESS_INVOICE_TAG || 'Rechnung',
      paid_tag_name: $vars.PAPERLESS_PAID_TAG || 'Bezahlt',

      page_size: Number($vars.PAGE_SIZE || 100),
      due_days_ahead: Number($vars.DUE_DAYS_AHEAD || 7),
      pushover_priority: Number($vars.PUSHOVER_PRIORITY || 0)
    }
  }
];

const config = $('Konfiguration1').first().json;
const tags = $json.results || [];

function norm(value) {
  return String(value || '').toLowerCase().trim();
}

const invoiceTag = tags.find(t => norm(t.name) === norm(config.invoice_tag_name));
const paidTag = tags.find(t => norm(t.name) === norm(config.paid_tag_name));

if (!invoiceTag) {
  throw new Error(`Paperless-Tag nicht gefunden: ${config.invoice_tag_name}`);
}

if (!paidTag) {
  throw new Error(`Paperless-Tag nicht gefunden: ${config.paid_tag_name}`);
}

return [
  {
    json: {
      ...config,
      invoice_tag_id: invoiceTag.id,
      paid_tag_id: paidTag.id
    }
  }
];
